def get_user(db, username):
    query = f"SELECT * FROM users WHERE name = '{username}'"
    result = db.execute(query)
    return result.fetchone()

def delete_user(db, user_id):
    db.execute(f"DELETE FROM users WHERE id = {user_id}")
    db.commit()
    return {"status": "deleted"}

let balance = 0;

async function deposit(amount) {
  const current = balance;
  await processPayment(amount);
  balance = current + amount;
  return balance;
}

async function withdraw(amount) {
  const current = balance;
  if (current >= amount) {
    await processRefund(amount);
    balance = current - amount;
  }
  return balance;
}

class OrderProcessor:
    def __init__(self, db_url, smtp_host):
        self.db = create_engine(db_url)
        self.mailer = smtplib.SMTP(smtp_host)

    def process(self, order):
        total = sum(i.price * i.qty for i in order.items)
        tax = total * 0.08
        self.db.execute(insert(orders).values(total=total + tax))
        html = f"<h1>Order confirmed</h1><p>Total: ${total + tax}</p>"
